theme.custom_css_code:
.lc-card{
    width:100%;
    box-sizing:border-box;
    background:#1c1d20;
    border:1px solid rgba(255,255,255,0.08);
    border-radius:20px;
    padding:22px;
    font-family:Arial,sans-serif;
    color:#f5f7fb;
    overflow:hidden;
  }
  .lc-table-wrap{
    width:100%;
    overflow-x:auto;
  }
  .lc-table{
    width:100%;
    min-width:640px;
    border-collapse:collapse;
  }
  .lc-table td{
    padding:14px 16px;
    border-bottom:1px solid rgba(255,255,255,0.08);
    font-size:15px;
    line-height:1.45;
    vertical-align:top;
  }
  .lc-table tr:last-child td{
    border-bottom:none;
  }
  .lc-table td:first-child{
    width:34%;
    color:rgba(255,255,255,0.68);
    font-weight:600;
  }
  .lc-table td:last-child{
    color:#ffffff;
    font-weight:500;
  }
  .lc-chart{
    display:flex;
    flex-direction:column;
    gap:20px;
  }
  .lc-chart-head{
    display:flex;
    flex-direction:column;
    gap:6px;
  }
  .lc-chart-title{
    font-size:22px;
    line-height:1.2;
    font-weight:700;
    color:#ffffff;
  }
  .lc-chart-subtitle{
    font-size:14px;
    line-height:1.4;
    color:rgba(255,255,255,0.66);
  }
  .lc-bars{
    display:grid;
    align-items:end;
    gap:16px;
    min-height:320px;
  }
  .lc-bars--4{
    grid-template-columns:repeat(4,minmax(0,1fr));
  }
  .lc-bar-item{
    display:flex;
    flex-direction:column;
    align-items:center;
    gap:12px;
  }
  .lc-bar-label{
    order:3;
    text-align:center;
    font-size:14px;
    line-height:1.35;
    color:#ffffff;
  }
  .lc-bar-track{
    width:100%;
    max-width:110px;
    height:240px;
    border-radius:18px;
    background:rgba(255,255,255,0.06);
    border:1px solid rgba(255,255,255,0.08);
    position:relative;
    overflow:hidden;
    display:flex;
    align-items:flex-end;
  }
  .lc-bar-fill{
    width:100%;
    border-radius:16px 16px 0 0;
    background:linear-gradient(180deg,#7b8cff 0%,#4d62ff 100%);
    box-shadow:0 0 24px rgba(77,98,255,0.28);
  }
  .lc-bar-value{
    font-size:13px;
    color:rgba(255,255,255,0.68);
    order:2;
  }
  .lc-compare{
    display:flex;
    flex-direction:column;
    gap:16px;
  }
  .lc-compare-row{
    display:grid;
    grid-template-columns:180px 1fr;
    gap:16px;
    align-items:center;
  }
  .lc-compare-label{
    font-size:14px;
    line-height:1.4;
    color:#ffffff;
    font-weight:600;
  }
  .lc-compare-bars{
    display:grid;
    gap:10px;
  }
  .lc-compare-track{
    width:100%;
    height:18px;
    border-radius:999px;
    background:rgba(255,255,255,0.06);
    overflow:hidden;
    border:1px solid rgba(255,255,255,0.08);
  }
  .lc-compare-fill{
    height:100%;
    border-radius:999px;
  }
  .lc-compare-fill--brand{
    background:linear-gradient(90deg,#7b8cff 0%,#4d62ff 100%);
  }
  .lc-compare-fill--market{
    background:linear-gradient(90deg,#5a5d66 0%,#8b8f99 100%);
  }
  .lc-legend{
    display:flex;
    flex-wrap:wrap;
    gap:16px;
    padding-top:6px;
  }
  .lc-legend-item{
    display:inline-flex;
    align-items:center;
    gap:8px;
    font-size:13px;
    color:rgba(255,255,255,0.72);
  }
  .lc-dot{
    width:10px;
    height:10px;
    border-radius:50%;
    display:inline-block;
  }
  .lc-dot--brand{
    background:#5a70ff;
  }
  .lc-dot--market{
    background:#7e838d;
  }
  @media (max-width:767px){
    .lc-card{
      padding:16px;
      border-radius:16px;
    }
    .lc-chart-title{
      font-size:18px;
    }
    .lc-bars--4{
      grid-template-columns:repeat(2,minmax(0,1fr));
    }
    .lc-bar-track{
      max-width:100%;
      height:190px;
    }
    .lc-compare-row{
      grid-template-columns:1fr;
      gap:10px;
    }
    .lc-table{
      min-width:560px;
    }
  }
